package main

import (
	"html/template"
	"net/http"
)

// Pre-parse the template once at package initialization to avoid re-parsing on each request
// The template automatically escapes injected data to prevent XSS attacks
var searchResultsTemplate = template.Must(template.New("searchResults").Parse(`<!DOCTYPE html>
<html>
<head>
<title>Product Search Results</title>
</head>
<body>
<h2>Search Results: {{.}}</h2>
</body>
</html>
`))

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Set the Content-Type header explicitly to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Execute the template with the keyword, which auto-escapes the input
	if err := searchResultsTemplate.Execute(w, keyword); err != nil {
		// Handle template execution errors with a 500 Internal Server Error
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
	}
}

