package main

import (
	"html"
	"net/http"
	"sync"
	"time"
)

// SearchEvent records a user's search activity
type SearchEvent struct {
	Keyword   string
	Timestamp time.Time
}

var (
	searchHistory []SearchEvent
	historyMu     sync.Mutex
)

// HandleProductSearch serves the product search results page with analytics tracking
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract and sanitize search keyword
	keyword := r.URL.Query().Get("keyword")

	// Record search event with thread safety
	historyMu.Lock()
	searchHistory = append(searchHistory, SearchEvent{
		Keyword:   keyword,
		Timestamp: time.Now(),
	})
	historyMu.Unlock()

	// Set HTML content type
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape keyword to prevent XSS attacks
	escapedKeyword := html.EscapeString(keyword)

	// Write HTML response
	w.Write([]byte(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search Results</title>
</head>
<body>
    <h2>Search Results: ` + escapedKeyword + `</h2>
    <p>View search analytics <a href="/analytics">here</a>.</p>
</body>
</html>`))
}

// HandleAnalytics serves the search analytics page
func HandleAnalytics(w http.ResponseWriter, r *http.Request) {
	// Safely access search history
	historyMu.Lock()
	defer historyMu.Unlock()

	// Set HTML content type
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Start HTML response
	w.Write([]byte(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Analytics</title>
</head>
<body>
    <h2>Search History Analytics</h2>
    <ul>`))

	// Add each search event to the list
	for _, event := range searchHistory {
		escapedKeyword := html.EscapeString(event.Keyword)
		formattedTime := event.Timestamp.Format(time.RFC1123)
		w.Write([]byte(`<li>` + escapedKeyword + ` - ` + formattedTime + `</li>`))
	}

	// End HTML response
	w.Write([]byte(`</ul>
    <p>Back to <a href="/search">product search</a>.</p>
</body>
</html>`))
}

func main() {
	// Register handlers
	http.HandleFunc("/search", HandleProductSearch)
	http.HandleFunc("/analytics", HandleAnalytics)

	// Start server on port 8080
	http.ListenAndServe(":8080", nil)
}

