package main

import (
	"html"
	"html/template"
	"log"
	"net/http"
	"time"
)

// searchData holds the dynamic data for the search results template
type searchData struct {
	Keyword   string
	Timestamp time.Time
}

// Pre-compiled template (safe for concurrent use)
var tpl *template.Template

func init() {
	// Parse the HTML template once at startup
	const searchTemplate = `
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search: {{.Keyword}}</title>
</head>
<body>
    <h2>Search Results: {{.Keyword}}</h2>
    <p>Search processed at: {{.Timestamp.Format "2006-01-02 15:04:05 UTC"}}</p>
</body>
</html>`
	var err error
	tpl, err = template.New("searchResults").Parse(searchTemplate)
	if err != nil {
		log.Fatalf("Failed to parse template: %v", err)
	}
}

// logSearchAnalytics is a placeholder for analytics integration (uses standard log)
func logSearchAnalytics(keyword, remoteAddr string, ts time.Time) {
	log.Printf("ANALYTICS: Search Event | Keyword=%q | RemoteAddr=%q | Time=%s",
		html.EscapeString(keyword),
		remoteAddr,
		ts.Format(time.RFC3339),
	)
}

// HandleProductSearch implements the product search results handler
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract keyword from URL query parameter
	keyword := r.URL.Query().Get("keyword")
	now := time.Now().UTC()

	// Trigger analytics tracking
	logSearchAnalytics(keyword, r.RemoteAddr, now)

	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Prepare template data
	data := searchData{
		Keyword:   keyword,
		Timestamp: now,
	}

	// Execute the template with data (automatically escapes HTML to prevent XSS)
	if err := tpl.Execute(w, data); err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		log.Printf("Template execution failed: %v", err)
		return
	}
}

func main() {
	// Register the search handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server
	log.Println("Server starting on :8080 - access via /search?keyword=your-search-term")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

