package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch handles product search requests and provides analytics
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Extract and escape search keyword to prevent XSS
	keyword := r.URL.Query().Get("keyword")
	escapedKeyword := html.EscapeString(keyword)

	// Analytics: Log search event with timestamp, keyword, and remote address
	log.Printf(
		"[Search Analytics] Time: %s | Keyword: %q | Remote Address: %s",
		time.Now().Format(time.RFC3339),
		escapedKeyword,
		r.RemoteAddr,
	)

	// Generate and write HTML response
	fmt.Fprintf(w, `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search Results</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <p>Thank you for searching our product catalog.</p>
    <!-- Additional product listing content would go here -->
</body>
</html>`, escapedKeyword)
}

func main() {
	// Register the search handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server
	log.Println("Server starting on port 8080...")
	log.Println("Access search at: http://localhost:8080/search?keyword=your-keyword")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

