package main

import (
	"encoding/json"
	"html/template"
	"log"
	"net/http"
	"time"
)

// SearchAnalytics holds analytics data for product search requests
type SearchAnalytics struct {
	Keyword     string    `json:"keyword"`
	Timestamp   time.Time `json:"timestamp"`
	RemoteAddr  string    `json:"remote_addr"`
	UserAgent   string    `json:"user_agent"`
}

// Pre-parse the HTML template once for efficiency
var searchResultsTemplate = template.Must(template.New("searchResults").Parse(`
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search Results</title>
</head>
<body>
    <h2>Search Results: {{.Keyword}}</h2>
    <p>Your search request has been processed. Results will appear here.</p>
</body>
</html>
`))

// logAnalytics records and outputs search analytics data
func logAnalytics(analytics SearchAnalytics) {
	jsonData, err := json.MarshalIndent(analytics, "", "  ")
	if err != nil {
		log.Printf("Error marshaling analytics data: %v", err)
		return
	}
	log.Printf("New Search Analytics Entry:\n%s", jsonData)
}

// HandleProductSearch handles HTTP requests for product search
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Extract search keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Collect analytics data
	analytics := SearchAnalytics{
		Keyword:    keyword,
		Timestamp:  time.Now().UTC(),
		RemoteAddr: r.RemoteAddr,
		UserAgent:  r.UserAgent(),
	}
	logAnalytics(analytics)

	// Prepare template data
	templateData := struct {
		Keyword string
	}{
		Keyword: keyword,
	}

	// Execute the template with the data
	if err := searchResultsTemplate.Execute(w, templateData); err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		log.Printf("Template execution error: %v", err)
		return
	}
}

func main() {
	// Register the search handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server on port 8080
	log.Println("Server starting on http://localhost:8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

