package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch handles product search requests, displays results, and logs analytics
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract search keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")
	// Escape keyword to prevent XSS vulnerabilities
	safeKeyword := html.EscapeString(keyword)

	// Log search analytics (server-side tracking)
	log.Printf(
		"Analytics: Product Search | Keyword=%q | Time=%s | RemoteAddr=%s | UserAgent=%q",
		keyword,
		time.Now().Format(time.RFC3339),
		r.RemoteAddr,
		r.UserAgent(),
	)

	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Write HTML response
	fmt.Fprintf(w, `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search Results</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <p>Your search results will be displayed here (demo placeholder).</p>
</body>
</html>`, safeKeyword)
}

func main() {
	// Register the search handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server
	log.Println("Server starting on :8080 - visit http://localhost:8080/search?keyword=your-keyword to test")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatalf("Failed to start server: %v", err)
	}
}

