package main

import (
	"encoding/json"
	"html"
	"log"
	"net/http"
	"time"
)

// SearchEvent represents an analytics event for product searches
type SearchEvent struct {
	Timestamp  time.Time `json:"timestamp"`
	Keyword    string    `json:"keyword"`
	RemoteAddr string    `json:"remote_addr"`
	UserAgent  string    `json:"user_agent"`
}

// HandleProductSearch handles product search requests with analytics
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract search keyword from query parameters
	keyword := r.URL.Query().Get("keyword")

	// Log analytics event
	event := SearchEvent{
		Timestamp:  time.Now().UTC(),
		Keyword:    keyword,
		RemoteAddr: r.RemoteAddr,
		UserAgent:  r.UserAgent(),
	}
	eventJSON, err := json.Marshal(event)
	if err != nil {
		log.Printf("error marshaling search analytics event: %v", err)
	} else {
		log.Printf("search analytics: %s", eventJSON)
	}

	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape keyword to prevent XSS attacks
	escapedKeyword := html.EscapeString(keyword)

	// Generate and write HTML response
	response := `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search Results</title>
</head>
<body>
    <h2>Search Results: ` + escapedKeyword + `</h2>
    <p>Product listings would appear here</p>
</body>
</html>`
	w.Write([]byte(response))
}

func main() {
	// Register search handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start server
	log.Println("Server starting on :8080, access via /search?keyword=your_query")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

