import (
	"encoding/json"
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// AnalyticsEvent represents a search event for analytics tracking
type AnalyticsEvent struct {
	Timestamp   time.Time `json:"timestamp"`
	Keyword     string    `json:"keyword"`
	RemoteAddr  string    `json:"remote_addr"`
	UserAgent   string    `json:"user_agent"`
}

// HandleProductSearch handles product search requests with analytics support
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set HTML content type
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Get and escape search keyword to prevent XSS
	keyword := r.URL.Query().Get("keyword")
	escapedKeyword := html.EscapeString(keyword)

	// Track analytics event
	event := AnalyticsEvent{
		Timestamp:  time.Now().UTC(),
		Keyword:    keyword,
		RemoteAddr: r.RemoteAddr,
		UserAgent:  r.UserAgent(),
	}
	eventJSON, err := json.Marshal(event)
	if err != nil {
		log.Printf("Failed to marshal analytics event: %v", err)
	} else {
		log.Printf("Search Analytics: %s", eventJSON)
	}

	// Write HTML response
	fmt.Fprintf(w, `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search Results</title>
    <style>
        body { font-family: Arial, sans-serif; max-width: 800px; margin: 2rem auto; padding: 0 1rem; }
        h2 { color: #2d3748; border-bottom: 2px solid #e2e8f0; padding-bottom: 0.5rem; }
        q { font-style: italic; color: #2b6cb0; }
    </style>
</head>
<body>
    <h2>Search Results: %s</h2>
    <p>Your search for <q>%s</q> has been processed and tracked for analytics.</p>
</body>
</html>`, escapedKeyword, escapedKeyword)
}

func main() {
	// Register the search handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	log.Println("Server starting on :8080 - visit http://localhost:8080/search?keyword=your-keyword to test")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

