// HandleProductSearch handles product search requests with analytics support
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set response content type to HTML with proper charset
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Extract search keyword from URL query parameter
	keyword := r.URL.Query().Get("keyword")
	// Escape keyword to prevent XSS attacks
	escapedKeyword := html.EscapeString(keyword)

	// Analytics: Log search event (server-side analytics placeholder)
	log.Printf(
		"[Analytics] Search Query - Timestamp: %s, Remote Address: %s, Keyword: %q",
		time.Now().Format(time.RFC3339),
		r.RemoteAddr,
		keyword,
	)

	// HTML template for search results page
	const htmlTemplate = `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search Results</title>
    <style>
        body {
            font-family: 'Arial', sans-serif;
            max-width: 900px;
            margin: 3rem auto;
            padding: 0 1.5rem;
            line-height: 1.6;
            color: #333;
        }
        .search-header {
            border-bottom: 2px solid #e0e0e0;
            padding-bottom: 1rem;
            margin-bottom: 2rem;
        }
        .search-header h2 {
            margin: 0;
            color: #2d3748;
        }
        .results-placeholder {
            padding: 1.5rem;
            background-color: #f7fafc;
            border-radius: 8px;
            border: 1px solid #e2e8f0;
        }
    </style>
</head>
<body>
    <div class="search-header">
        <h2>Search Results: %s</h2>
    </div>
    <div class="results-container">
        <div class="results-placeholder">
            <p>Product search results matching your query will be displayed here.</p>
        </div>
    </div>
</body>
</html>`

	// Render the HTML template with escaped keyword
	_, err := fmt.Fprintf(w, htmlTemplate, escapedKeyword)
	if err != nil {
		log.Printf("Error writing search results response: %v", err)
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}
}

func main() {
	// Register the product search handler to the /search route
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server on port 8080
	const serverPort = ":8080"
	log.Printf("Product search server starting on %s", serverPort)
	log.Printf("Test the server at: http://localhost%s/search?keyword=wireless-headphones", serverPort)

	// Listen and serve, log fatal if server fails to start
	log.Fatal(http.ListenAndServe(serverPort, nil))
}

