package main

import (
	"fmt"
	"html"
	"net/http"
	"sync"
	"time"
)

// SearchRecord stores analytics data for product searches
type SearchRecord struct {
	Keyword string    // The original search keyword
	Time    time.Time // Timestamp of the search
}

var (
	searchAnalytics []SearchRecord // In-memory storage for search analytics
	analyticsMu     sync.Mutex     // Mutex to ensure thread-safe access to analytics
)

// HandleProductSearch handles HTTP requests for product search results
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract search keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")
	// Escape keyword to prevent cross-site scripting (XSS) vulnerabilities
	escapedKeyword := html.EscapeString(keyword)

	// Record search analytics in a thread-safe manner
	analyticsMu.Lock()
	searchAnalytics = append(searchAnalytics, SearchRecord{
		Keyword: keyword,
		Time:    time.Now(),
	})
	analyticsMu.Unlock()

	// Set response content type to HTML with proper charset
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Generate and write the HTML response
	fmt.Fprintf(w, `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Product Search Results</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <p>Your search has been processed and recorded for analytics purposes.</p>
</body>
</html>`, escapedKeyword)
}

func main() {
	// Register the product search handler to the "/search" route
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server on port 8080
	fmt.Println("Server starting on http://localhost:8080")
	fmt.Println("Example usage: http://localhost:8080/search?keyword=laptop")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Printf("Server failed to start: %v\n", err)
	}
}

