func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract search keyword from query parameters
	keyword := r.URL.Query().Get("keyword")

	// Log basic analytics: timestamp, search keyword, and client address
	log.Printf("Search Analytics: time=%s, keyword=%q, remote_addr=%s",
		time.Now().Format(time.RFC3339),
		keyword,
		r.RemoteAddr,
	)

	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape keyword to prevent XSS attacks
	escapedKeyword := html.EscapeString(keyword)

	// Generate and write HTML response
	response := `<!DOCTYPE html>
<html lang="en">
