    <h2>Search Results: ` + escapedKeyword + `</h2>
    <p>Demo product search results page (analytics logged server-side)</p>
</body>
</html>`
	w.Write([]byte(response))
}

func main() {
	// Register the search handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start server on port 8080
	log.Println("Server starting on :8080. Access via http://localhost:8080/search?keyword=your-keyword")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

